{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a complex optimization task involving spatial reasoning, probabilistic inference (due to noisy queries), and cost-minimization strategy. It requires decomposing the search space and the decision-making process.",
  "helpers": [
    {
      "label": "spatial_pattern_matching",
      "instructions": "Analyze the set of known polyomino shapes. Identify potential overlap patterns, symmetries, and the minimum/maximum possible bounding boxes for the oil fields. Determine how different placements of these polyominoes could interact or overlap on a grid."
    },
    {
      "label": "probabilistic_query_strategy",
      "instructions": "Develop a strategy for using 'noisy aggregate queries' to maximize information gain per unit cost. Model the noise level and determine how many queries are needed at specific coordinates or regions to reach a confidence threshold for identifying the presence of a polyomino."
    },
    {
      "label": "cost_optimization_model",
      "instructions": "Formulate a decision tree or a greedy algorithm that balances the high cost of 'drilling' (direct cell probing) against the lower cost but higher uncertainty of 'noisy aggregate queries'. The goal is to minimize the expected total cost: E[Cost] = Cost(Drilling) + Cost(Queries) + Penalty(Incorrect Guesses)."
    },
    {
      "label": "reconstruction_algorithm",
      "instructions": "Given the results of the spatial matching and the probabilistic queries, design an algorithm to reconstruct the most likely set of oil-containing cells. This should involve a Bayesian update approach where each query result updates the probability map of the grid."
    }
  ],
  "synthesis_brief": "Combine the spatial constraints (possible placements) with the probabilistic information gathered from queries to create a probability map of the grid. Use the cost-optimization model to select the sequence of actions (drilling vs. querying) that minimizes the expected cost to reach a high-confidence reconstruction of the oil cells. The final answer should be the set of coordinates identified as oil-containing cells."
}
```

